#include <iostream>
#include <stdexcept>
#include <string>

class FileError : public std::runtime_error {
public:
    int error_code;
    FileError(const std::string& msg, int code)
        : std::runtime_error(msg), error_code(code) {}
};

void trigger(int code) {
    if (code == 1) throw FileError("file not found", 404);
    if (code == 2) throw std::runtime_error("generic error");
}

int main() {
    int code;
    std::cin >> code;

    try {
        trigger(code);
        std::cout << "ok\n";
    } catch (const FileError& e) {
        std::cout << "FileError " << e.error_code << ": " << e.what() << "\n";
    } catch (const std::runtime_error& e) {
        std::cout << "runtime: " << e.what() << "\n";
    }

    return 0;
}

